#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int N=1e6+6;

int n,a,b,c,x[N],s[N];
ll f[N];

ll cal(int j){
    return -f[j]-1LL*a*s[j]*s[j]+1LL*b*s[j];
}

int main(){
    scanf("%d%d%d%d",&n,&a,&b,&c);
    for(int i=1;i<=n;i++){
        scanf("%d",&x[i]);
        s[i]=s[i-1]+x[i];
    }
    int q[N],hh=1,tt=1;
    q[hh]=0;
    for(int i=1;i<=n;i++){
        while(hh<tt && cal(q[hh])-cal(q[hh+1])>=1LL*(-2)*a*s[i]*(s[q[hh]]-s[q[hh+1]]))//注意负数对不等式的影响
            hh++;
        int j=q[hh];
        f[i]=f[j]+1LL*a*(s[i]-s[j])*(s[i]-s[j])+1LL*b*(s[i]-s[j])+c;
        //printf("%d\n",f[i]);
        while(hh<tt && (cal(q[tt])-cal(q[tt-1]))*(s[q[tt]]-s[i])<=(cal(q[tt])-cal(i))*(s[q[tt]]-s[q[tt-1]]))
            tt--;
        q[++tt]=i;
    }
    printf("%lld",f[n]);
    return 0;
}
